mapper.sql:
where i.project_id = #{projectId}


	and i.issue_type_id = #{issueTypeId}



	and i.version_id = #{versionId}



	and lower(i.title) like '%' || lower(#{keyword}) || '%'



	and i.issue_status_id = #{issueStatusId}



	and i.setting_code_id = #{settingCodeId}



	and i.assignee_id = #{assigneeId}



	and i.progress_rate = #{progressRate}



	and trunc(i.start_date) >=
	#{startDate}



	and trunc(i.due_date) <=
	#{dueDate}

mapper.select:
select * from ( select rownum as row_no, issue_list.* from ( select i.issue_id, i.issue_no, '#' || lpad(to_char(i.issue_no), 4, '0') as display_issue_no, i.issue_type_id, it.issue_type_name, i.version_id, v.version_name, i.title, i.issue_status_id, ist.status_name as issue_status_name, ist.closed_yn, i.setting_code_id, sc.setting_name, i.assignee_id, assignee.user_name as assignee_name, i.progress_rate, i.start_date, i.due_date, i.estimated_hours, i.project_id, p.project_name, i.author_id, author.user_name as author_name, i.created_at, i.updated_at, i.milestone_id, m.title as milestone_title, i.parent_issue_id, parent_issue.title as parent_issue_title from issue i join project p on i.project_id = p.project_id left join issue_type it on i.issue_type_id = it.issue_type_id left join issue_status ist on i.issue_status_id = ist.issue_status_id left join setting_code sc on i.setting_code_id = sc.setting_code_id left join users assignee on i.assignee_id = assignee.user_id left join users author on i.author_id = author.user_id left join project_version v on i.version_id = v.version_id and i.project_id = v.project_id left join milestone m on i.milestone_id = m.milestone_id and i.project_id = m.project_id left join issue parent_issue on i.parent_issue_id = parent_issue.issue_id and i.project_id = parent_issue.project_id
order by i.issue_no asc
order by i.issue_no desc
) issue_list where rownum <= #{endRow} ) where row_no >= #{startRow}

select distinct x.assignee_id, x.assignee_name from ( select u.user_id as assignee_id, u.user_name as assignee_name from project_member pm join team_member tm on pm.team_member_id = tm.team_member_id join users u on tm.user_id = u.user_id where pm.project_id = #{projectId}
union
select owner_user.user_id as assignee_id, owner_user.user_name as assignee_name from project p join users owner_user on p.owner_id = owner_user.user_id where p.project_id = #{projectId} ) x order by x.assignee_name, x.assignee_id

select count(*)
from project_version
where project_id = #{projectId}
and version_id =
#{versionId}
and status_code != 'k003'

select
count(*)
from issue
where project_id = #{projectId}
and issue_id =
#{parentIssueId}

select count(*)
from
issue
where project_id = #{projectId}
and parent_issue_id = #{issueId}

mapper.delete:
delete from issue
where project_id = #{projectId}
and
issue_id = #{issueId}
